// Get MBA specializations for a university
export function getMBASpecs(uniId: string): string[] {
  return MBA_SPECS[uniId] || []
}

// Get MBA syllabus for a university and specialization
export function getMBASyllabus(uniId: string, spec?: string): MBASyllabus | Record<string, MBASyllabus> | null {
  const uniSyllabus = MBA_SYLLABUS[uniId]
  if (!uniSyllabus) return null
  if (spec) return uniSyllabus[spec] || null
  return uniSyllabus
}
